const begin21 = (x1,y1,x2,y2,x3,y3) => {
    const d=(ax,ay,bx,by)=>Math.sqrt((bx-ax)**2+(by-ay)**2);
    const a=d(x1,y1,x2,y2), b=d(x2,y2,x3,y3), c=d(x3,y3,x1,y1), p=(a+b+c)/2;
    return [a+b+c, Math.sqrt(p*(p-a)*(p-b)*(p-c))];
};

