public static double[] begin21(double x1, double y1, double x2, double y2, double x3, double y3) {
    double a=Math.sqrt(Math.pow(x2-x1,2)+Math.pow(y2-y1,2)), b=Math.sqrt(Math.pow(x3-x2,2)+Math.pow(y3-y2,2)), c=Math.sqrt(Math.pow(x1-x3,2)+Math.pow(y1-y3,2));
    double p=(a+b+c)/2.0; return new double[]{a+b+c, Math.sqrt(p*(p-a)*(p-b)*(p-c))};
}

